mapper.select:
SELECT sw.ID, sw.WORD, sw.TYPE, sw.LEVEL, sw.STATUS, sw.REMARK, sw.CREATE_USER, sw.CREATE_TIME, sw.UPDATE_USER, sw.UPDATE_TIME, (SELECT u.USERNAME FROM user u WHERE u.ID = sw.CREATE_USER) AS CREATE_USERNAME, (SELECT u.USERNAME FROM user u WHERE u.ID = sw.UPDATE_USER) AS UPDATE_USERNAME FROM sensitive_word sw
AND sw.WORD LIKE #{v}
AND sw.STATUS = #{query.status}
ORDER BY sw.CREATE_TIME DESC
